161	// loggedEvent is the on-disk shape of a single line in worker-events.jsonl.
162	// Wraps the worker-supplied event with the receiving worker_id and the
163	// server's timestamp.
164	type loggedEvent struct {
165		WorkerID  string          `json:"worker_id"`
166		Timestamp time.Time       `json:"timestamp"`
167		BeadID    string          `json:"bead_id,omitempty"`
168		AttemptID string          `json:"attempt_id,omitempty"`
169		Kind      string          `json:"kind"`
170		Body      json.RawMessage `json:"body,omitempty"`
171	}
172	
173	func (r *workerIngestRegistry) append(workerID string, ev workerEvent) error {
174		r.mu.Lock()
175		defer r.mu.Unlock()
176		r.openOnce.Do(func() {
177			if err := os.MkdirAll(filepath.Dir(r.logPath), 0o755); err != nil {
178				r.openErr = err
179				return
180			}
181			f, err := os.OpenFile(r.logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
182			if err != nil {
183				r.openErr = err
184				return
185			}
186			r.logFile = f
187		})
188		if r.openErr != nil {
189			return r.openErr
190		}
191		line, err := json.Marshal(loggedEvent{
192			WorkerID:  workerID,
193			Timestamp: time.Now().UTC(),
194			BeadID:    ev.BeadID,
195			AttemptID: ev.AttemptID,
196			Kind:      ev.Kind,
197			Body:      ev.Body,
198		})
199		if err != nil {
200			return err
201		}
202		line = append(line, '\n')
203		_, err = r.logFile.Write(line)
204		return err
205	}
206	
207	// close releases the log file handle. Safe to call when the file was
208	// never opened. Used on server shutdown / test cleanup.
209	func (r *workerIngestRegistry) close() error {
210		r.mu.Lock()
211		defer r.mu.Unlock()
212		if r.logFile == nil {
213			return nil
214		}
215		err := r.logFile.Close()
216		r.logFile = nil
217		return err
218	}
