220	func newWorkerID() string {
221		var b [12]byte
222		if _, err := rand.Read(b[:]); err != nil {
223			// crypto/rand failure is unrecoverable; fall back to a timestamp
224			// stub so the path is non-empty (registration still succeeds and
225			// the operator sees a malformed-looking ID in the UI).
226			return fmt.Sprintf("wkr-%d", time.Now().UnixNano())
227		}
228		return "wkr-" + hex.EncodeToString(b[:])
229	}
