233	func (s *Server) handleWorkerRegister(w http.ResponseWriter, r *http.Request) {
234		var id workerIdentity
235		if err := decodeWorkerIngestBody(r, &id); err != nil {
236			writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
237			return
238		}
239		if id.ProjectRoot == "" {
240			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "project_root required"})
241			return
242		}
243		rec := s.workerIngest.register(id)
244		writeJSON(w, http.StatusOK, map[string]string{"worker_id": rec.WorkerID})
245	}
